// Lookup helper: returns { q: "Q1"|null, scopus: true|false } or null if not found
export function lookupJournalByISSN(issnList) {
  if (!issnList || !Array.isArray(issnList)) return null;
  for (const raw of issnList) {
    if (!raw) continue;
    // Normalize ISSN format: ensure XXXX-XXXX with dash
    let issn = String(raw).trim().toUpperCase().replace(/-/g, "");
    if (issn.length !== 8) continue;
    issn = issn.slice(0, 4) + "-" + issn.slice(4);
    const code = JOURNAL_DATA[issn];
    if (!code) continue;
    const qMap = { "1":"Q1", "2":"Q2", "3":"Q3", "4":"Q4" };
    const q = qMap[code[0]] || null;
    const scopus = code.includes("S");
    return { q, scopus, matchedIssn: issn };
  }
  return null;
}
